{
 "level": "A1–B1",
 "intro": "Learn the main question types in English.",
 "rules": [
 {
 "label": "Yes / No",
 "color": "emerald",
 "text": "<strong>General questions</strong> with yes / no answers:",
 "example": "Do you like coffee?"
 },
 {
 "label": "Wh",
 "color": "blue",
 "text": "<strong>Wh-questions</strong> with question words:",
 "example": "What do you want?"
 },
 {
 "label": "Tags & Negatives",
 "color": "rose",
 "text": "<strong>Question tags</strong> and <strong>negative questions</strong> for confirmation or surprise:",
 "example": "You know him, don't you? / Don't you know him?"
 }
 ]
}
